import React from 'react';

const LOGO_MARK_DATA_URI = "data:image/png;base64,";

/**
 * Futuro del Este — Logo
 * The circular wave mark, optionally paired with the stacked wordmark.
 * The mark is embedded so it works with zero asset wiring.
 */
export function Logo({
  variant = 'lockup',     // 'mark' | 'lockup' | 'lockup-horizontal'
  size = 48,
  tone = 'navy',          // wordmark color: 'navy' | 'white'
  style = {},
  ...rest
}) {
  const wordColor = tone === 'white' ? '#FFFFFF' : 'var(--fde-navy)';
  const delColor = tone === 'white' ? 'rgba(255,255,255,0.7)' : 'var(--fde-cyan)';

  const Mark = (
    <img
      src={LOGO_MARK_DATA_URI}
      alt="Futuro del Este"
      width={size}
      height={size}
      style={{ display: 'block', borderRadius: '50%', flexShrink: 0 }}
    />
  );

  if (variant === 'mark') {
    return <span style={{ display: 'inline-flex', ...style }} {...rest}>{Mark}</span>;
  }

  const wordmarkStacked = (
    <span style={{
      display: 'flex', flexDirection: 'column', lineHeight: 1,
      fontFamily: 'var(--font-sans)', textTransform: 'uppercase',
    }}>
      <span style={{
        fontSize: size * 0.26, fontWeight: 500, letterSpacing: '0.18em',
        color: wordColor, opacity: 0.85,
      }}>Fundación</span>
      <span style={{ fontSize: size * 0.42, fontWeight: 800, letterSpacing: '0.04em', color: wordColor }}>
        Futuro<span style={{ fontWeight: 500, color: delColor }}>del</span>Este
      </span>
    </span>
  );

  const wordmarkHorizontal = (
    <span style={{
      display: 'flex', flexDirection: 'column', lineHeight: 1.05,
      fontFamily: 'var(--font-sans)', textTransform: 'uppercase',
      fontWeight: 800, letterSpacing: '0.12em', color: wordColor,
      fontSize: size * 0.3,
    }}>
      <span>Futuro</span>
      <span style={{ fontWeight: 500, letterSpacing: '0.22em' }}>del Este</span>
    </span>
  );

  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: size * 0.28, ...style }} {...rest}>
      {Mark}
      {variant === 'lockup-horizontal' ? wordmarkHorizontal : wordmarkStacked}
    </span>
  );
}
